INSERT INTO `services` (`id`, `order`, `parent_id`, `image_url`, `title`, `slug`, `content`, `meta_tags`, `created_at`, `updated_at`, `meta_title`, `meta_description`, `meta_keywords`) VALUES
(16, 1, NULL, 'uploads/services/1778332616_69ff33c8dcea5.webp', 'Love Problem Solution by Astrologer Ankit Shastri Ji | Get Your Love Back', 'love-problem-solution-by-astrologer-ankit-shastri-ji-get-your-love-back', '<p class=\"p1\">Love is one of the most beautiful feelings in life ❤️, but when problems enter a relationship, it can bring pain, confusion, and stress. Many people face heartbreak, misunderstandings, or separation from their loved ones. If you are struggling in your love life, <span class=\"s1\"><strong>Astrologer Ankit Shastri Ji</strong></span> is here to guide you with powerful and effective solutions 🔮.</p>\r\n<h3><span class=\"s1\"><strong>🌟 Expert Love Problem Solutions</strong></span></h3>\r\n<p class=\"p1\">Astrologer Ankit Shastri Ji has years of experience in solving complex love and relationship issues. With deep knowledge of astrology, he provides accurate predictions and remedies that help bring back love, trust, and happiness in your life.</p>\r\n<h3><span class=\"s1\"><strong>💔 Problems We Solve</strong></span></h3>\r\n<ul>\r\n<li>One-sided love issues</li>\r\n<li>Breakup and patch-up problems</li>\r\n<li>Get your ex love back</li>\r\n<li>Love marriage problems</li>\r\n<li>Family opposition in love marriage</li>\r\n<li>Husband-wife disputes</li>\r\n<li>Trust issues and misunderstandings</li>\r\n</ul>\r\n<h3><span class=\"s1\"><strong>🔮 Powerful Astrological Remedies</strong></span></h3>\r\n<p class=\"p3\">Using proven Vedic astrology methods, Ankit Shastri Ji offers personalized solutions such as:</p>\r\n<ul>\r\n<li>Kundli analysis for love compatibility</li>\r\n<li>Love marriage specialist guidance</li>\r\n<li>Vashikaran remedies for love attraction</li>\r\n<li>Black magic removal and protection</li>\r\n<li>Mantra and spiritual remedies</li>\r\n</ul>\r\n<h3><span class=\"s1\"><strong>❤️ Why Choose Ankit Shastri Ji?</strong></span></h3>\r\n<ul>\r\n<li>100% confidential consultation 🤝</li>\r\n<li>Quick and effective results</li>\r\n<li>Trusted by thousands of happy clients</li>\r\n<li>Available for online consultation worldwide 🌍</li>\r\n<li>Personalized solutions for every problem</li>\r\n</ul>\r\n<h3><span class=\"s1\"><strong>📞 Contact Now for Immediate Help</strong></span></h3>\r\n<p class=\"p1\">Don&rsquo;t let love problems control your life. Take the first step towards happiness and reunite with your loved one today.</p>\r\n<p class=\"p4\">📲 <span class=\"s1\"><strong>Call / WhatsApp:</strong></span><br>🇮🇳 +91 9915585892<br>🇨🇦 +1 437-776-6381</p>', NULL, '2026-04-18 17:36:09', '2026-05-09 18:32:23', 'Love Problem Solution by Astrologer Ankit Shastri Ji | Get Your Love Back', 'Facing breakup or love issues? Get expert solutions from Astrologer Ankit Shastri Ji. Call now.', 'love problem solution, get ex back, relationship issues solution'),
(17, 2, NULL, 'uploads/services/1778332925_69ff34fd23474.webp', 'Marriage Problem Solution | Expert Astrologer Ankit Shastri Ji', 'marriage-problem-solution-expert-astrologer-ankit-shastri-ji', '<p>Marriage is a sacred bond that brings two souls together ❤️, but sometimes misunderstandings, conflicts, and external pressures can create serious problems. If your married life is facing challenges,&nbsp;<strong>Astrologer Ankit Shastri Ji</strong> offers powerful and effective solutions to restore peace, love, and harmony in your relationship 🔮.</p>\r\n<h2>🌟 Trusted Marriage Problem Specialist</h2>\r\n<p>With years of experience in astrology and relationship guidance, Astrologer Ankit Shastri Ji has helped many couples overcome their marital issues. His accurate predictions and personalized remedies help resolve even the most complicated marriage problems.</p>\r\n<h2>💔 Common Marriage Problems We Solve</h2>\r\n<ul>\r\n<li>Husband and wife disputes</li>\r\n<li>Lack of love and understanding</li>\r\n<li>Extra-marital affairs</li>\r\n<li>Frequent arguments and conflicts</li>\r\n<li>Family interference in married life</li>\r\n<li>Divorce problems and separation issues</li>\r\n<li>Trust issues and emotional distance</li>\r\n</ul>\r\n<h2>🔮 Effective Astrological Remedies</h2>\r\n<ul>\r\n<li>Kundli matching and analysis</li>\r\n<li>Remedies to strengthen husband-wife bond</li>\r\n<li>Love and trust rebuilding solutions</li>\r\n<li>Vashikaran remedies for relationship improvement</li>\r\n<li>Black magic removal and protection</li>\r\n<li>Mantra and spiritual guidance</li>\r\n</ul>\r\n<h2>❤️ Why Choose Ankit Shastri Ji?</h2>\r\n<ul>\r\n<li>100% private and confidential consultation 🤝</li>\r\n<li>Fast and result-oriented solutions</li>\r\n<li>Trusted by thousands of happy clients</li>\r\n<li>Online consultation available worldwide 🌍</li>\r\n<li>Personalized remedies for every situation</li>\r\n</ul>\r\n<h2>📞 Contact Now for Immediate Help</h2>\r\n<p>Don&rsquo;t let marriage problems destroy your happiness. Take the right step today and bring peace and stability back into your married life.</p>\r\n<p><strong>Call / WhatsApp:</strong><br>🇮🇳 +91 9915585892<br>🇨🇦 +1 437-776-6381</p>\r\n<h2>🔥 Save Your Marriage Today!</h2>\r\n<p>With the blessings and expert guidance of Astrologer Ankit Shastri Ji, you can resolve all your marriage problems and rebuild a strong, loving relationship 💖</p>', NULL, '2026-04-18 17:39:11', '2026-05-09 18:32:24', 'Marriage Problem Solution | Expert Astrologer Ankit Shastri Ji', 'Facing marriage issues? Get trusted solutions and restore peace now.', 'marriage problem solution, husband wife dispute, save marriage'),
(18, 3, NULL, 'uploads/services/1778333295_69ff366fac141.webp', 'Black Magic Removal Specialist | Astrologer Ankit Shastri Ji', 'black-magic-removal-specialist-astrologer-ankit-shastri-ji', '<p>Negative energies and black magic can disturb your life in many ways 😔. It can affect your health, relationships, career, and mental peace. If you are facing sudden problems, bad luck, or unexplained issues, <strong>Astrologer Ankit Shastri Ji</strong> provides powerful and effective solutions to remove black magic and protect your life 🔮.</p>\r\n<h2>🌟 Expert in Black Magic Removal</h2>\r\n<p>Astrologer Ankit Shastri Ji is a trusted specialist in removing black magic and negative energies. With deep knowledge of Vedic astrology and spiritual practices, he helps people get relief from harmful effects and restores positivity in their lives.</p>\r\n<h2>⚠️ Signs of Black Magic Effects</h2>\r\n<ul>\r\n<li>Sudden bad luck and continuous failures</li>\r\n<li>Health problems without medical reason</li>\r\n<li>Relationship issues and unwanted conflicts</li>\r\n<li>Financial losses and business problems</li>\r\n<li>Feeling negative, stressed, or depressed</li>\r\n<li>Disturbed sleep or scary dreams</li>\r\n<li>Unexplained fear and anxiety</li>\r\n</ul>\r\n<h2>🔮 Powerful Black Magic Removal Solutions</h2>\r\n<ul>\r\n<li>Complete black magic removal remedies</li>\r\n<li>Negative energy cleansing</li>\r\n<li>Protection from evil eye (Nazar Dosha)</li>\r\n<li>Spiritual healing and aura cleansing</li>\r\n<li>Mantra and puja solutions</li>\r\n<li>Personalized astrology-based remedies</li>\r\n</ul>\r\n<h2>🛡️ Protection &amp; Positive Energy</h2>\r\n<p>Along with removing black magic, Astrologer Ankit Shastri Ji also provides strong protection remedies to keep you safe from future negative energies and ensure peace, success, and happiness in your life.</p>\r\n<h2>❤️ Why Choose Ankit Shastri Ji?</h2>\r\n<ul>\r\n<li>100% confidential consultation 🤝</li>\r\n<li>Quick and effective solutions</li>\