INSERT INTO `testimonials` (`id`, `order`, `name`, `image_url`, `content`, `created_at`, `updated_at`) VALUES
(5, 1, 'Rahul Sharma', 'uploads/testimonials/1778322750_69ff0d3e547b6.webp', '<p class=\"p1\">Mere relationship mein bahut problems chal rahi thi aur main apne partner ko lose karne wala tha. Ankit Shastri Ji ki guidance se sab theek ho gaya. Aaj hum phir se khush hain. Highly recommended!</p>', '2026-04-15 10:43:10', '2026-05-09 16:02:30'),
(6, 2, 'Aman Gupta', 'uploads/testimonials/1778323093_69ff0e95c0ea7.webp', '<p class=\"p1\">Mera business kaafi loss mein chal raha tha. Ankit Shastri Ji se consult karne ke baad dheere dheere sab improve hone laga. Ab mera business grow kar raha hai.</p>', '2026-04-15 10:43:34', '2026-05-09 16:08:13'),
(7, 3, 'Priya Verma', 'uploads/testimonials/1778322898_69ff0dd22dd65.webp', '<p class=\"p1\">Bilkul accurate prediction aur effective solutions. Mere marriage issues solve ho gaye aur ab meri life peaceful aur happy hai. Thank you so much!</p>', '2026-04-15 10:43:43', '2026-05-09 16:04:58'),
(8, 4, 'Neha Kapoor', 'uploads/testimonials/1778323237_69ff0f252cb0d.webp', '<p class=\"p1\">Main apne career ko leke bahut confused tha. Jo guidance mili usse mujhe sahi direction mila aur ab main apni job mein achha kar raha hoon.</p>', '2026-04-22 18:59:23', '2026-05-09 16:10:37'),
(9, 5, 'Vikram Singh', 'uploads/testimonials/1778323180_69ff0eecc891c.webp', '<p class=\"p1\">Maine apna ex love wapas pa liya Ankit Shastri Ji ki help se. Unke remedies bahut powerful hain. Bahut acha experience raha!</p>', '2026-04-22 19:00:11', '2026-05-09 16:09:40'),
(10, 6, 'Simran Kaur', 'uploads/testimonials/1778323364_69ff0fa428671.webp', '<p class=\"p1\">Bahut professional aur trustworthy service hai. Consultation private tha aur remedies kaafi effective rahe. Ab main kaafi positive feel karta hoon.</p>', '2026-04-22 19:00:36', '2026-05-09 16:12:44'),
(11, 7, 'Rohit Malhotra', 'uploads/testimonials/1778323819_69ff116bf2f5e.webp', '<p class=\"p1\">Mujhe abroad jaane mein delay ho raha tha, lekin guidance follow karne ke baad mera visa approve ho gaya. Bahut thankful hoon!</p>', '2026-04-22 19:00:57', '2026-05-09 16:20:19'),
(12, 8, 'Pooja Arora', 'uploads/testimonials/1778323835_69ff117bc1833.webp', '<p class=\"p1\">Love aur relationship problems ke liye best astrologer. Mujhe jaldi results mile aur meri life ab kaafi better hai.</p>', '2026-04-22 19:01:20', '2026-05-09 16:20:35');

